import React from 'react';
import DataTable from '../../components/common/DataTable';
import { createResourceService } from '../../services/api.service';
import Icon from '../../components/common/Icon';
import { icons } from '../../config/icons';

const clientService = createResourceService('clients');
const employeeService = createResourceService('employees');

const Pending = () => {
    // const tableConfig = useMemo(() => ({hasHeader:false, hasFooter:false, hasPagination:false, tableControls:false, searchables: ['fn|mn|sn', 'phone', 'email'] }), []); 
    const initialLoadTime = React.useMemo(() => Date.now(), []);

    const clientColumns = React.useMemo(() => [
        {
            key: 'fn', label: 'Full Name', type: 0, class: 'mob-flex', sortable: true, render: (item, photoUrl) => {
                let displayUrl = photoUrl || '/defaults/avatar.png';
                if (displayUrl.includes('?')) displayUrl = displayUrl.split('?')[0];
                displayUrl = `${displayUrl}?t=${initialLoadTime}`;

                return (
                    <div className='td-user'>
                        <div className='td-user-photo'><img src={displayUrl} alt={`${item.fn} ${item.sn}`} loading='lazy' onError={(e) => { e.target.onerror = null; e.target.src = '/defaults/avatar.png'; }} /></div>
                        <div className='tr-name'><b>{`${item.fn} ${item.mn ? item.mn : ''} ${item.sn}`}</b><p>{item.email}</p> </div>
                    </div>
                );
            }
        },
        { key: 'address', label: 'Address', type: 1, class: 'mob-full', sortable: true },
    ], [initialLoadTime]);

    const employeeColumns = React.useMemo(() => [
        {
            key: 'fn', label: 'Employee Name', type: 0, class: 'mob-flex', sortable: true, render: (item, photoUrl) => {
                let displayUrl = photoUrl || '/defaults/avatar.png';
                if (displayUrl.includes('?')) displayUrl = displayUrl.split('?')[0];
                displayUrl = `${displayUrl}?t=${initialLoadTime}`;

                return (
                    <div className='td-user'>
                        <div className='tr-name'><b>{`${item.fn} ${item.mn ? item.mn : ''} ${item.sn}`}</b><p>{item.email}</p> </div>
                    </div>
                );
            }
        },
        { key: 'phone', label: 'Phone', type: 1, class: 'mob-full', sortable: true },
    ], [initialLoadTime]);

    return (<div className="admin-pager">
        <header className="admin-pager-head">
            <div className='admin-pager-title'> <span><h2>Multiple Table</h2><p>Custom Table for Pages</p></span> </div>
        </header>
        <div className='admin-pager-body'>
            <div className='pagelet'>
                <div className='pagelet-head'> <h4><Icon icon={icons.users} />Clients</h4> </div>
                <div className='wrap'>
                    <DataTable
                        resourceName='Client'
                        apiService={clientService}
                        columns={clientColumns}
                        config={{ class: 'multiple-table', hasHeader: false, hasFooter: false, hasPagination: false, tableControls: false, hasTHead: false, hasRowAction: false, searchables: ['fn|mn|sn', 'email'], }}
                    />
                </div>
            </div>
            <div className='pagelet'>
                <div className='pagelet-head'> <h4><Icon icon={icons.users} />Employees</h4> </div>
                <div className='wrap'>
                    <DataTable
                        resourceName='Employee'
                        apiService={employeeService}
                        columns={employeeColumns}
                        config={{ class: 'multiple-table', hasHeader: false, hasFooter: false, hasPagination: false, tableControls: false, hasRowAction: false, searchables: ['fn|mn|sn', 'email'], }} />
                </div>
            </div>
        </div>
    </div>);
};

export default Pending;